module RefModule (  
    input clk,  
    input reset,  
    input start,  
    input [7:0] src_address,  
    input [7:0] dest_address,  
    output reg done  
);  
    reg [2:0] pipeline_reg;  
    parameter IDLE = 3'b000, TRANSFER = 3'b001, COMPLETE = 3'b010;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            pipeline_reg <= IDLE;  
            done <= 0;  
        end else begin  
            case (pipeline_reg)  
                IDLE: begin  
                    if (start) begin  
                        pipeline_reg <= TRANSFER;  
                        done <= 0;  
                    end  
                end  
                TRANSFER: begin  
                    // Simulate data transfer process here  
                    pipeline_reg <= COMPLETE;  
                end  
                COMPLETE: begin  
                    done <= 1;  
                    pipeline_reg <= IDLE;  
                end  
                default: pipeline_reg <= IDLE;  
            endcase  
        end  
    end  
endmodule
